3	import { Text } from '@mantine/core';
4	import { axisBottom } from 'd3-axis';
5	import { type ScaleBand, scaleBand } from 'd3-scale';
6	import { select, type Selection } from 'd3-selection';
7	import { useRouter } from 'next/navigation';
8	import { useCallback, useEffect, useMemo, useRef } from 'react';
9	
10	import { formatDate, getNarrowMonthName, getShortMonthName } from '@/lib/dates';
11	import { type PlayerFormType } from '@/types';
12	
13	import styles from './PlayerHeatmap.module.css';
14	
15	export interface Props {
16	    /**
17	     * Outcomes to visualise. Every entry must have a populated `gameDay`
18	     * (including a native `Date` object for `gameDay.date` — Prisma returns
19	     * `Date`, but JSON-serialised props will have a string and will not render
20	     * correctly). Entries whose `gameDay.game` is `false` represent scheduled
21	     * days on which no game took place; they are shown in light grey and
22	     * navigate to the game day details page on click. Entries with
23	     * `points === null` and `game === true` represent days the player was
24	     * invited but did not play.
25	     */
26	    data: PlayerFormType[];
27	    /**
28	     * The calendar year being displayed, or `0` for the all-time view.
29	     *
30	     * - When `year > 0` the chart renders a single panel with months (Jan–Dec)
31	     *   on the X axis and game-number-within-month on the Y axis.
32	     * - When `year === 0` year panels are laid out side by side, wrapping to
33	     *   the next row when the viewport width is exhausted, most recent year first.
34	     */
35	    year: number;
36	}
37	
38	interface Cell {
39	    col: string;
40	    row: number;
41	    points: number | null | undefined;
42	    noGame: boolean;
43	    date: Date;
44	    gameId: number;
45	    comment: string | null | undefined;
46	}
47	
48	const colorMap = new Map<number | null | undefined, string>([
49	    [null, 'var(--mantine-color-gray-5)'],
50	    [undefined, 'var(--mantine-color-gray-5)'],
51	    [0, 'var(--mantine-color-red-6)'],
52	    [1, 'var(--mantine-color-yellow-5)'],
53	    [3, 'var(--mantine-color-green-6)'],
54	]);
55	
56	const NO_GAME_COLOR = 'var(--mantine-color-gray-3)';
57	
58	const resultLabel = new Map<number | null | undefined, string>([
59	    [null, 'Did not play'],
60	    [undefined, 'Did not play'],
61	    [0, 'Lost'],
62	    [1, 'Drew'],
63	    [3, 'Won'],
64	]);
65	
66	// Short names are the unique domain keys; narrow names are used for axis display.
67	const MONTH_COLS = Array.from({ length: 12 }, (_, i) => getShortMonthName(2000, i + 1));
68	const SHORT_TO_NARROW = new Map(
69	    MONTH_COLS.map((short, i) => [short, getNarrowMonthName(2000, i + 1)]),
70	);
71	
72	/** Builds the flat cell list for a single year's data (always month columns). */
73	export function buildGrid(data: PlayerFormType[]): { cells: Cell[]; maxRow: number } {
74	    const grouped = new Map<string, PlayerFormType[]>();
75	
76	    for (const entry of data) {
77	        if (!entry.gameDay) continue;
78	        const date = new Date(entry.gameDay.date);
79	        const col = getShortMonthName(date.getFullYear(), date.getMonth() + 1);
80	        const list = grouped.get(col) ?? [];
81	        list.push(entry);
82	        grouped.set(col, list);
83	    }
84	
85	    const cells: Cell[] = [];
86	    let maxRow = 0;
87	
88	    for (const col of MONTH_COLS) {
89	        const entries = (grouped.get(col) ?? []).sort(
90	            (a, b) => new Date(a.gameDay!.date).getTime() - new Date(b.gameDay!.date).getTime(),
91	        );
92	        entries.forEach((entry, i) => {
93	            cells.push({
94	                col,
95	                row: i + 1,
96	                points: entry.points ?? null,
97	                noGame: entry.gameDay!.game === false,
98	                date: new Date(entry.gameDay!.date),
99	                gameId: entry.gameDay!.id,
100	                comment: entry.gameDay?.comment,
101	            });
102	        });
103	        maxRow = Math.max(maxRow, entries.length);
104	    }
105	
106	    return { cells, maxRow };
107	}
108	
109	/**
110	 * Groups data by year, builds a cell list for each year, and returns an array of year groups
111	 * sorted in reverse chronological order.
112	 */
113	export function buildYearGroups(data: PlayerFormType[]): { year: string; cells: Cell[]; maxRow: number }[] {
114	    const byYear = new Map<string, PlayerFormType[]>();
115	    for (const entry of data) {
116	        if (!entry.gameDay) continue;
117	        const yr = String(new Date(entry.gameDay.date).getFullYear());
118	        const list = byYear.get(yr) ?? [];
119	        list.push(entry);
120	        byYear.set(yr, list);
121	    }
122	    return Array.from(byYear.keys())
123	        .sort((a, b) => Number(b) - Number(a))
124	        .map(yr => ({ year: yr, ...buildGrid(byYear.get(yr)!) }));
125	}
126	
127	const GAP = 2;
128	const CELL_SIZE = 10;
129	const M = { top: 4, right: 10, bottom: 24, left: 4 };
130	const YEAR_LABEL_HEIGHT = 22;
131	
132	interface TooltipContent {
133	    date: string;
134	    label: string;
135	    comment?: string | null;
136	}
137	
138	type ShowTooltip = (event: globalThis.MouseEvent, content: TooltipContent) => void;
139	
140	/**
141	 * Returns an X scale for the month columns, along with the calculated inner
142	 * width (excluding margins) needed to fit the columns at the specified cell
143	 * size and gap. The scale's domain is the short month names (e.g., "Jan",
144	 * "Feb") and its range is [0, innerWidth]. The scale's bandwidth is the cell
145	 * size, and its paddingInner is set to create the specified gap between cells.
146	 * The caller can use the returned inner width to set the SVG width and the
147	 * scale to position cells and axis ticks.
148	 *
149	 * @returns An object containing the configured X scale and the calculated inner
150	 * width.
151	 */
152	function makeXScale(): { scale: ScaleBand<string>; iw: number } {
153	    const n = MONTH_COLS.length;
154	    const iw = n * CELL_SIZE + (n - 1) * GAP;
155	    const paddingInner = GAP / (CELL_SIZE + GAP);
156	    const scale = scaleBand()
157	        .domain(MONTH_COLS)
158	        .range([0, iw])
159	        .paddingInner(paddingInner);
160	    return { scale, iw };
161	}
162	
163	function drawPanel(
164	    g: Selection<SVGGElement, unknown, null, undefined>,
165	    cells: Cell[],
166	    maxRow: number,
167	    xScale: ScaleBand<string>,
168	    showTooltip: ShowTooltip,
169	    hideTooltip: () => void,
170	    onCellClick: (gameId: number) => void,
171	) {
172	    const cellSize = xScale.bandwidth();
173	    const ih = maxRow * cellSize + Math.max(0, maxRow - 1) * GAP;
174	
175	    // X axis — domain keys are short names; labels are rendered as narrow single letters
176	    g.append('g')
177	        .attr('transform', `translate(0,${ih + 4})`)
178	        .call(axisBottom(xScale).tickSize(0).tickFormat(d => SHORT_TO_NARROW.get(d)!))
179	        .call(ax => { ax.select('.domain').remove(); });
180	
181	    // Cells
182	    g.selectAll<SVGRectElement, Cell>('rect.cell')
183	        .data(cells)
184	        .enter()
185	        .append('rect')
186	        .attr('class', 'cell')
187	        .attr('x', d => xScale(d.col)!)
188	        .attr('y', d => (d.row - 1) * (cellSize + GAP))
189	        .attr('width', xScale.bandwidth())
190	        .attr('height', cellSize)
191	        .attr('rx', 2)
192	        .attr('role', 'button')
193	        .attr('tabindex', '0')
194	        .attr('aria-label', d => {
195	            if (d.noGame) {
196	                const status = d.comment ? `No game — ${d.comment}` : 'No game';
197	                return `${formatDate(d.date)} – ${status}`;
198	            }
199	            return `${formatDate(d.date)} – ${resultLabel.get(d.points) ?? ''}`;
200	        })
201	        .style('fill', d => d.noGame ? NO_GAME_COLOR : (colorMap.get(d.points) ?? 'var(--mantine-color-gray-5)'))
202	        .style('cursor', 'pointer')
203	        .on('mousemove', (event: globalThis.MouseEvent, d) => {
204	            showTooltip(event, {
205	                date: formatDate(d.date),
206	                label: d.noGame ? 'No game' : (resultLabel.get(d.points) ?? ''),
207	                comment: d.noGame ? d.comment : undefined,
208	            });
209	        })
210	        .on('mouseleave', hideTooltip)
211	        .on('click', (_, d) => { onCellClick(d.gameId); })
212	        .on('keydown', (event: globalThis.KeyboardEvent, d) => {
213	            if (event.key === 'Enter' || event.key === ' ') {
214	                event.preventDefault();
215	                onCellClick(d.gameId);
216	            }
217	        });
218	}
219	
220	interface YearPanelProps {
221	    label: string;
222	    cells: Cell[];
223	    globalMaxRow: number;
224	    showTooltip: ShowTooltip;
225	    hideTooltip: () => void;
226	}
227	
228	/**
229	 * Renders a panel for a single year in the player's heatmap.
230	 *
231	 * @param props - See {@link YearPanelProps}.
232	 */
233	const YearPanel = ({ label, cells, globalMaxRow, showTooltip, hideTooltip }: YearPanelProps) => {
234	    const svgRef = useRef<SVGSVGElement>(null);
235	    const router = useRouter();
236	
237	    useEffect(() => {
238	        /* c8 ignore next */
239	        if (!svgRef.current) return;
240	        const onCellClick = (gameId: number) => router.push(`/footy/game/${gameId}`);
241	        const { scale: xScale, iw } = makeXScale();
242	        const cellSize = xScale.bandwidth();
243	        const ih = globalMaxRow * cellSize + Math.max(0, globalMaxRow - 1) * GAP;
244	        const w = iw + M.left + M.right;
245	        const h = YEAR_LABEL_HEIGHT + M.top + ih + M.bottom;
246	
247	        const svg = select(svgRef.current);
248	        svg.selectAll('*').remove();
249	        svg.attr('width', w).attr('height', h);
250	
251	        svg.append('text')
252	            .attr('x', M.left)
253	            .attr('y', YEAR_LABEL_HEIGHT - 4)
254	            .style('font-size', '14px')
255	            .style('font-weight', '600')
256	            .style('fill', 'currentColor')
257	            .text(label);
258	
259	        const g = svg.append('g').attr('transform', `translate(${M.left},${YEAR_LABEL_HEIGHT + M.top})`);
260	        drawPanel(g, cells, globalMaxRow, xScale, showTooltip, hideTooltip, onCellClick);
261	    }, [cells, globalMaxRow, hideTooltip, label, router, showTooltip]);
262	
263	    return <svg ref={svgRef} />;
264	};
265	
266	/**
267	 * Renders a D3 heatmap of a player's game history.
268	 *
269	 * Each cell represents one game day, coloured by result:
270	 * - Green  — won (points = 3)
271	 * - Yellow — draw (points = 1)
272	 * - Grey   — invited but did not play (points = null, game = true)
273	 * - Red    — lost (points = 0)
274	 * - Light grey — no game took place (gameDay.game = false)
275	 *
276	 * Clicking or pressing Enter/Space on any cell navigates to the corresponding
277	 * game page (`/footy/game/[id]`). No-game cells show the game day comment in
278	 * the tooltip when one is available.
279	 *
280	 * In the all-time view (`year === 0`) year panels are arranged side by side,
281	 * wrapping to the next row when the available width is exhausted. In a
282	 * single-year view (`year > 0`) one panel is rendered inline.
283	 *
284	 * @param props - See {@link Props}.
285	 */
286	export const PlayerHeatmap = ({ data, year }: Props) => {
287	    const wrapperRef = useRef<HTMLDivElement>(null);
288	    const tooltipRef = useRef<HTMLDivElement>(null);
289	    const svgRef = useRef<SVGSVGElement>(null);
290	    const router = useRouter();
291	
292	    const showTooltip = useCallback(
293	        (event: globalThis.MouseEvent, { date, label, comment }: TooltipContent) => {
294	            const el = tooltipRef.current;
295	            const wrapper = wrapperRef.current;
296	            /* c8 ignore next */
297	            if (!el || !wrapper) return;
298	            const wrapperRect = wrapper.getBoundingClientRect();
299	
300	            // Build content with text nodes — avoids innerHTML / XSS risk.
301	            el.textContent = '';
302	            const b = document.createElement('b');
303	            b.textContent = date;
304	            el.appendChild(b);
305	            el.appendChild(document.createElement('br'));
306	            el.appendChild(document.createTextNode(label));
307	            if (comment) {
308	                el.appendChild(document.createElement('br'));
309	                el.appendChild(document.createTextNode(comment));
310	            }
311	
312	            el.style.left = `${event.clientX - wrapperRect.left}px`;
313	            el.style.top = `${event.clientY - wrapperRect.top + 16}px`;
314	            el.style.opacity = '1';
315	        },
316	        [],
317	    );
318	
319	    const hideTooltip = useCallback(() => {
320	        /* c8 ignore next */
321	        if (tooltipRef.current) tooltipRef.current.style.opacity = '0';
322	    }, []);
323	
324	    // Single-year drawing
325	    useEffect(() => {
326	        if (year === 0 || !svgRef.current) return;
327	        const onCellClick = (gameId: number) => router.push(`/footy/game/${gameId}`);
328	        const { cells, maxRow } = buildGrid(data);
329	        if (maxRow === 0) return;
330	        const { scale: xScale, iw } = makeXScale();
331	        const cellSize = xScale.bandwidth();
332	        const ih = maxRow * cellSize + Math.max(0, maxRow - 1) * GAP;
333	        const w = iw + M.left + M.right;
334	        const svg = select(svgRef.current);
335	        svg.selectAll('*').remove();
336	        svg.attr('width', w).attr('height', ih + M.top + M.bottom);
337	        const g = svg.append('g').attr('transform', `translate(${M.left},${M.top})`);
338	        drawPanel(g, cells, maxRow, xScale, showTooltip, hideTooltip, onCellClick);
339	    }, [data, hideTooltip, router, showTooltip, year]);
340	
341	    const yearGroups = useMemo(
342	        () => year === 0 ? buildYearGroups(data) : null,
343	        [data, year],
344	    );
345	    const globalMaxRow = useMemo(
346	        () => yearGroups ? Math.max(0, ...yearGroups.map(yg => yg.maxRow)) : 0,
347	        [yearGroups],
348	    );
349	
350	    if (data.length === 0) {
351	        return <Text c="dimmed" ta="center" py="xl">No game data available.</Text>;
352	    }
353	
354	    if (year === 0) {
355	        return (
356	            <div ref={wrapperRef} className={styles.allTimeWrapper}>
357	                {yearGroups!.map(({ year: yr, cells }) => (
358	                    <YearPanel
359	                        key={yr}
360	                        label={yr}
361	                        cells={cells}
362	                        globalMaxRow={globalMaxRow}
363	                        showTooltip={showTooltip}
364	                        hideTooltip={hideTooltip}
365	                    />
366	                ))}
367	                <div ref={tooltipRef} className={styles.tooltip} />
368	            </div>
369	        );
370	    }
371	
372	    return (
373	        <div ref={wrapperRef} className={styles.wrapper}>
374	            <svg ref={svgRef} />
375	            <div ref={tooltipRef} className={styles.tooltip} />
376	        </div>
377	    );
378	};
