import prisma from 'prisma/prisma';
import {
    OutcomeWhereUniqueInputObjectSchema,
    PlayerResponseSchema,
    TeamName,
    TeamNameSchema,
} from 'prisma/zod/schemas';
import {
    OutcomeType,
} from 'prisma/zod/schemas/models/Outcome.schema';
import z from 'zod';

import { InternalError } from '@/lib/errors';
import { isPrismaNotFoundError } from '@/lib/prismaErrors';
import gameDayService from '@/services/GameDay';
import {
    PlayerFormType,
    TeamPlayerSchema,
    type TeamPlayerType,
    Turnout,
    TurnoutByYearType,
    WDLType,
} from '@/types';
import { OutcomePlayerType } from '@/types/OutcomePlayerType';
import {
    OutcomeCreateOneStrictSchema,
    OutcomeUpsertOneStrictSchema,
    type OutcomeWriteInput,
    OutcomeWriteInputSchema,
} from '@/types/OutcomeStrictSchema';

/** Linear merge of two PlayerFormType arrays already sorted by date then id. */
function mergeByDate(a: PlayerFormType[], b: PlayerFormType[]): PlayerFormType[] {
    const result: PlayerFormType[] = [];
    let i = 0;
    let j = 0;
    while (i < a.length && j < b.length) {
        const dateDiff = a[i].gameDay!.date.getTime() - b[j].gameDay!.date.getTime();
        if (dateDiff < 0 || (dateDiff === 0 && a[i].gameDay!.id <= b[j].gameDay!.id)) {
            result.push(a[i++]);
        } else {
            result.push(b[j++]);
        }
    }
    while (i < a.length) result.push(a[i++]);
    while (j < b.length) result.push(b[j++]);
    return result;
}

class OutcomeService {
    /**
