48	/**
49	 * Splits a comma-separated email string into a normalized list of emails.
50	 *
51	 * Normalization trims whitespace, removes empty entries, and lowercases all
52	 * email addresses.
53	 *
54	 * @param rawEmail - A comma-separated list of emails from legacy data.
55	 * @returns A normalized list of email addresses.
56	 */
57	function splitEmailList(rawEmail: string | null): string[] {
58	    if (!rawEmail) {
59	        return [];
60	    }
61	    return rawEmail
62	        .split(',')
63	        .map((email) => email.trim())
64	        .filter((email) => email.length > 0)
65	        .map((email) => email.toLowerCase());
66	}
67	
68	
69	/**
70	 * Builds seed data for `account.email` and `playerExtraEmail` from legacy
71	 * player email values.
72	 *
73	 * The first unique email is treated as the account email and any remaining
74	 * unique emails are emitted as extra email rows. Duplicate emails already
75	 * assigned to another player are skipped.
76	 *
77	 * @param sources - Player IDs and raw legacy email strings.
78	 * @returns A map of primary account emails keyed by player ID and extra email
79	 * rows for seeding.
80	 */
81	function buildPlayerEmailSeeds(
82	    sources: { playerId: number; email: string | null }[],
83	): { accountEmailByPlayerId: Map<number, string>; extraEmailRows: PlayerExtraEmailSeed[] } {
84	    const extraEmailRows: PlayerExtraEmailSeed[] = [];
85	    const accountEmailByPlayerId = new Map<number, string>();
86	    const seen = new Map<string, number>();
87	
88	    sources.forEach((source) => {
89	        const emails = Array.from(new Set(splitEmailList(source.email)));
90	        if (emails.length === 0) return;
91	
92	        const [accountEmail, ...extraEmails] = emails;
93	
94	        if (accountEmail) {
95	            const existing = seen.get(accountEmail);
96	            if (existing && existing !== source.playerId) {
97	                console.warn(`Skipping duplicate account email ${accountEmail} for player ${source.playerId}; already assigned to player ${existing}`);
98	            } else {
99	                seen.set(accountEmail, source.playerId);
100	                accountEmailByPlayerId.set(source.playerId, accountEmail);
101	            }
102	        }
103	
104	        extraEmails.forEach((email) => {
105	            const existing = seen.get(email);
106	            if (existing && existing !== source.playerId) {
107	                console.warn(`Skipping duplicate extra email ${email} for player ${source.playerId}; already assigned to player ${existing}`);
108	                return;
109	            }
110	
111	            seen.set(email, source.playerId);
112	            extraEmailRows.push({
113	                playerId: source.playerId,
114	                email,
115	            });
116	        });
117	    });
118	
119	    return { accountEmailByPlayerId, extraEmailRows };
120	}
